import json
from statistics import mean

from app.llm.llm import generate_answer
from app.retrieval.retrieval_router import RetrievalRouter
from app.evaluation.metrics import compute_rouge_l, compute_bertscore_batch
from config import RETRIEVAL_TOP_K, RETRIEVAL_METHOD

# Load Json file from the determined path
def load_json(path):
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


# Evaluating the quality of answers generated by the system
def evaluate_answers():
    questions = load_json("data/questions.json")  # Load the questions
    ground_truth = load_json("data/ground_truth.json")  # Load the reference answers and correct documents
    # Transforming ground truth into an easily accessible dictionary via question_id
    gt_map = {item["question_id"]: item for item in ground_truth}
    retrieval_system = RetrievalRouter()  # Create a rollback prompt to select the rollback method from the config
    results = []  # Store the detailed results

    # Addressing each question individually
    for q in questions:
        # Retrieve the appropriate context for the question
        context, references = retrieval_system.retrieve_context_bundle(q["question"], RETRIEVAL_TOP_K)
        generated_answer = generate_answer(q["question"], context)   # Generating the answer using LLM
        reference_answer = gt_map[q["id"]]["reference_answer"]  # Get the reference answer
        rouge_l = compute_rouge_l(reference_answer, generated_answer)  # Calculate ROUGE-L

        # Temporarily store the result
        results.append(
            {
                "question_id": q["id"],
                "reference_answer": reference_answer,
                "generated_answer": generated_answer,
                "rouge_l": rouge_l,
            }
        )

    # After completing all the questions, we calculate the BERTScore all at once
    reference_answers = [r["reference_answer"] for r in results]
    generated_answers = [r["generated_answer"] for r in results]
    bertscore_values = compute_bertscore_batch(reference_answers, generated_answers)

    # Adding a BERTScore value to each result
    for i, score in enumerate(bertscore_values):
        results[i]["bertscore_f1"] = score

    # Calculating Final Averages
    summary = {
        "retrieval_method": RETRIEVAL_METHOD,
        "avg_rouge_l": mean(r["rouge_l"] for r in results),
        "avg_bertscore_f1": mean(r["bertscore_f1"] for r in results)
    }

    # Print Summary
    print(json.dumps(summary, indent=2))


if __name__ == "__main__":
    evaluate_answers()